<?php
session_start(); $conn=new mysqli("localhost","root","","agroconnect"); $conn->set_charset("utf8mb4");
require_once 'agro_helper.php';
if(!isset($_SESSION['rol'])){header("Location: login.php");exit();}
function existe($c,$t){$t=$c->real_escape_string($t);$r=$c->query("SHOW TABLES LIKE '$t'");return $r&&$r->num_rows>0;}
$sinTabla=!existe($conn,'incidencias'); $rol=$_SESSION['rol']; $uid=$_SESSION['id']??null; $eid=$_SESSION['empresa_id']??null;
if(!$sinTabla && isset($_POST['crear_incidencia'])){ $titulo=trim($_POST['titulo']); $desc=trim($_POST['descripcion']); $pri=$_POST['prioridad']; $emp=($rol=='superadmin'&&!empty($_POST['empresa_id']))?intval($_POST['empresa_id']):($eid?:null); $st=$conn->prepare("INSERT INTO incidencias (empresa_id,usuario_id,titulo,descripcion,prioridad) VALUES (?,?,?,?,?)"); $st->bind_param("iisss",$emp,$uid,$titulo,$desc,$pri); $st->execute(); header("Location: incidencias.php"); exit(); }
if(!$sinTabla && $rol=='superadmin' && isset($_POST['actualizar_estado'])){ $id=intval($_POST['id']); $estado=$_POST['estado']; $st=$conn->prepare("UPDATE incidencias SET estado=? WHERE id=?"); $st->bind_param("si",$estado,$id); $st->execute(); header("Location: incidencias.php"); exit(); }
$empresas=$conn->query("SELECT id,nombre FROM empresas ORDER BY nombre");
if(!$sinTabla){ if($rol=='superadmin') $inc=$conn->query("SELECT i.*,e.nombre empresa,u.nombre usuario FROM incidencias i LEFT JOIN empresas e ON i.empresa_id=e.id LEFT JOIN usuarios u ON i.usuario_id=u.id ORDER BY i.fecha_creacion DESC"); else { $eid=intval($eid); $inc=$conn->query("SELECT i.*,e.nombre empresa,u.nombre usuario FROM incidencias i LEFT JOIN empresas e ON i.empresa_id=e.id LEFT JOIN usuarios u ON i.usuario_id=u.id WHERE i.empresa_id=$eid ORDER BY i.fecha_creacion DESC"); }}
$volver=$rol=='superadmin'?'superadmin.php':($rol=='jefe'?'jefe.php':'trabajador.php');
?>
<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Incidencias</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet"><link rel="stylesheet" href="style.css"></head><body class="admin-body"><?php include __DIR__ . '/includes/topbar.php'; ?><div class="admin-container"><h2 class="admin-title">Gestión de incidencias</h2><?php if($sinTabla){ ?><div class="alert alert-warning">Importa <strong>actualizacion_superadmin.sql</strong> para activar esta sección.</div><?php }else{ ?><div class="dashboard-grid two-columns"><div class="admin-card"><h4>Nueva incidencia</h4><form method="POST"><?php if($rol=='superadmin'){ ?><div class="mb-3"><label class="form-label">Empresa</label><select name="empresa_id" class="form-select"><option value="">General</option><?php while($e=$empresas->fetch_assoc()){ ?><option value="<?php echo $e['id']; ?>"><?php echo htmlspecialchars($e['nombre']); ?></option><?php } ?></select></div><?php } ?><div class="mb-3"><label class="form-label">Título</label><input name="titulo" class="form-control" required></div><div class="mb-3"><label class="form-label">Descripción</label><textarea name="descripcion" class="form-control" rows="4" required></textarea></div><div class="mb-3"><label class="form-label">Prioridad</label><select name="prioridad" class="form-select"><option value="baja">Baja</option><option value="media" selected>Media</option><option value="alta">Alta</option></select></div><button name="crear_incidencia" class="btn btn-success w-100">Crear incidencia</button></form></div><div class="admin-card"><h4>Seguimiento</h4><p class="text-muted">El SuperAdmin puede revisar y cambiar el estado de cada incidencia.</p></div></div><div class="admin-card mt-4"><div class="table-responsive"><table class="table table-striped align-middle"><thead><tr><th>Título</th><th>Empresa</th><th>Usuario</th><th>Prioridad</th><th>Estado</th><th>Fecha</th><?php if(in_array($rol,['superadmin','jefe'])){ ?><th>Acción</th><?php } ?></tr></thead><tbody><?php while($i=$inc->fetch_assoc()){ ?><tr><td><strong><?php echo htmlspecialchars($i['titulo']); ?></strong><br><small class="text-muted"><?php echo htmlspecialchars($i['descripcion']); ?></small></td><td><?php echo htmlspecialchars($i['empresa']??'General'); ?></td><td><?php echo htmlspecialchars($i['usuario']??'Sistema'); ?></td><td><span class="badge bg-success"><?php echo htmlspecialchars($i['prioridad']); ?></span></td><td><?php echo htmlspecialchars($i['estado']); ?></td><td><?php echo date('d/m/Y H:i',strtotime($i['fecha_creacion'])); ?></td><?php if(in_array($rol,['superadmin','jefe'])){ ?><td><form method="POST" class="d-flex gap-2"><input type="hidden" name="id" value="<?php echo $i['id']; ?>"><select name="estado" class="form-select form-select-sm"><option value="abierta" <?php if($i['estado']=='abierta') echo 'selected'; ?>>Abierta</option><option value="en_revision" <?php if($i['estado']=='en_revision') echo 'selected'; ?>>En revisión</option><option value="resuelta" <?php if($i['estado']=='resuelta') echo 'selected'; ?>>Resuelta</option></select><button name="actualizar_estado" class="btn btn-success btn-sm">Guardar</button></form><div class="mt-2"><?php echo agro_crud_botones('incidencias', $i['id'], 'incidencias.php'); ?></div></td><?php } ?></tr><?php } ?></tbody></table></div></div><?php } ?></div><?php include __DIR__ . '/includes/footer.php'; ?>
</body></html>
